package com.cognizant.springlearn.security;
import java.io.IOException; import java.util.*; import org.springframework.security.authentication.UsernamePasswordAuthenticationToken; import org.springframework.security.core.authority.SimpleGrantedAuthority; import org.springframework.security.core.context.SecurityContextHolder; import org.springframework.stereotype.Component; import org.springframework.web.filter.OncePerRequestFilter; import io.jsonwebtoken.Claims; import jakarta.servlet.*; import jakarta.servlet.http.*;
@Component public class JwtAuthenticationFilter extends OncePerRequestFilter { private final JwtUtil jwtUtil; public JwtAuthenticationFilter(JwtUtil jwtUtil){this.jwtUtil=jwtUtil;} @Override protected void doFilterInternal(HttpServletRequest request,HttpServletResponse response,FilterChain chain) throws ServletException, IOException { String header=request.getHeader("Authorization"); if(header!=null && header.startsWith("Bearer ")){ try { Claims claims=jwtUtil.validateToken(header.substring(7)); String username=claims.getSubject(); @SuppressWarnings("unchecked") List<String> roles=(List<String>)claims.get("roles"); var authorities=roles.stream().map(SimpleGrantedAuthority::new).toList(); SecurityContextHolder.getContext().setAuthentication(new UsernamePasswordAuthenticationToken(username,null,authorities)); } catch(Exception ignored) { SecurityContextHolder.clearContext(); } } chain.doFilter(request,response); } }
